-- V120: public-portal i18n coverage — bulk EN/SW keys for the citizen-facing pages.
-- Idempotent upsert so re-running / re-seeding is safe (label_key is unique).
  values ('Public Pages', true, 90) on conflict (name) do nothing;

on conflict (label_key) do update set en = excluded.en, sw = excluded.sw,
  group_name = excluded.group_name, updated_at = now();
